1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Customer = { yearsWithMHPCO: number };
3	type QuoteInput = {
4	  customer: Customer;
5	  items: Item[];
6	  previousContracts: number;
7	};
8	
9	const PROCESSING_FEE = 5;
10	const NEWCOMER_PER_ITEM_SURCHARGE_RATE = 0.1;
11	
12	const basePremiumForItem = (item: Item): number => {
13	  if (item.type === "sword") return 100;
14	  return 0;
15	};
16	
17	const isNewcomer = (customer: Customer): boolean =>
18	  customer.yearsWithMHPCO === 0;
19	
20	const itemPremium = (item: Item, customer: Customer): number => {
21	  const base = basePremiumForItem(item);
22	  const surcharge = isNewcomer(customer) ? base * NEWCOMER_PER_ITEM_SURCHARGE_RATE : 0;
23	  return base + surcharge;
24	};
25	
26	export const quote = (input: QuoteInput): { premium: number } => {
27	  const itemsTotal = input.items.reduce(
28	    (sum, item) => sum + itemPremium(item, input.customer),
29	    0,
30	  );
31	  return { premium: itemsTotal + PROCESSING_FEE };
32	};
33	
34	export const claim = (_input: unknown): unknown => {
35	  return undefined;
36	};
